import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';

interface Particle {
  id: number;
  x: number;
  y: number;
  size: number;
  duration: number;
  delay: number;
}

export const Background: React.FC = () => {
  const [particles, setParticles] = useState<Particle[]>([]);

  useEffect(() => {
    // Initialize particles
    const newParticles = Array.from({ length: 15 }).map((_, i) => ({
      id: i,
      x: Math.random() * 100,
      y: Math.random() * 100,
      size: Math.random() * 4 + 2,
      duration: Math.random() * 10 + 10,
      delay: Math.random() * 5,
    }));
    setParticles(newParticles);
  }, []);

  return (
    <div className="fixed inset-0 w-full h-full z-0 overflow-hidden bg-[#0f0f23]">
      {/* Video Background */}
      <div className="absolute inset-0 w-full h-full">
         <video
            autoPlay
            loop
            muted
            playsInline
            className="w-full h-full object-cover opacity-40"
         >
            <source src="https://techbridge.edu.gh/static/videos/video-1037996266055286.mp4" type="video/mp4" />
         </video>

         {/* Overlays for readability and aesthetic tinting */}
         <div className="absolute inset-0 bg-[#0f0f23]/60 mix-blend-multiply" />
         <div className="absolute inset-0 bg-gradient-to-b from-[#0f0f23] via-transparent to-[#0f0f23]" />
      </div>

      {/* Floating Particles */}
      <div className="absolute inset-0 w-full h-full pointer-events-none">
        {particles.map((p) => (
          <motion.div
            key={p.id}
            className="absolute rounded-full bg-[#667eea]/40 blur-[1px]"
            style={{
              width: p.size,
              height: p.size,
              left: `${p.x}%`,
              top: `${p.y}%`,
            }}
            animate={{
              y: [0, -100],
              opacity: [0, 0.8, 0],
            }}
            transition={{
              duration: p.duration,
              repeat: Infinity,
              delay: p.delay,
              ease: "linear"
            }}
          />
        ))}
      </div>
    </div>
  );
};

