import React, { useState } from 'react';
import { Loader2, Send, AlertCircle } from 'lucide-react';
import { registerUser } from '../services/api';
import { RegistrationStatus } from '../types';
import { AddToCalendar } from './AddToCalendar';

export const RegistrationForm: React.FC = () => {
  const [email, setEmail] = useState('');
  const [status, setStatus] = useState<RegistrationStatus>(RegistrationStatus.IDLE);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const handleSubmit = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    setErrorMsg(null);

    if (!email) {
      setErrorMsg('Please enter your email address.');
      return;
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      setErrorMsg('Please enter a valid email address.');
      return;
    }

    setStatus(RegistrationStatus.LOADING);

    try {
      await registerUser(email);
      setStatus(RegistrationStatus.SUCCESS);
      setEmail('');
    } catch (error) {
      console.error(error);
      setStatus(RegistrationStatus.ERROR);
      setErrorMsg('Sorry, there was an error submitting your registration. Please try again or contact helpdesk@aucdt.edu.gh');
    }
  };

  if (status === RegistrationStatus.SUCCESS) {
    return <AddToCalendar />;
  }

  return (
    <div className="w-full mt-6 flex flex-col gap-3">
      <div className="flex flex-col sm:flex-row gap-4 w-full">
        <input
          type="email"
          value={email}
          onChange={(e) => {
            setEmail(e.target.value);
            if (status === RegistrationStatus.ERROR) setStatus(RegistrationStatus.IDLE);
            if (errorMsg) setErrorMsg(null);
          }}
          placeholder="Enter your email address"
          disabled={status === RegistrationStatus.LOADING}
          className={`flex-1 min-w-0 px-6 py-5 rounded-2xl border-2 ${errorMsg ? 'border-red-500/50 focus:border-red-500' : 'border-[#667eea]/20 focus:border-[#667eea]'} bg-white/80 backdrop-blur-sm text-lg font-medium text-slate-800 placeholder-slate-400 focus:outline-none focus:bg-white/95 focus:ring-4 focus:ring-[#667eea]/10 transition-all shadow-lg shadow-[#667eea]/10 disabled:opacity-60`}
          onKeyDown={(e) => e.key === 'Enter' && handleSubmit()}
        />
        <button
          onClick={() => handleSubmit()}
          disabled={status === RegistrationStatus.LOADING}
          className="relative overflow-hidden group bg-gradient-to-br from-[#667eea] to-[#764ba2] text-white px-8 py-5 rounded-2xl text-xl font-bold shadow-xl shadow-[#667eea]/30 transition-all hover:-translate-y-1 hover:shadow-2xl disabled:opacity-70 disabled:cursor-not-allowed whitespace-nowrap flex items-center justify-center gap-2"
        >
          {/* Shimmer effect */}
          <div className="absolute inset-0 -translate-x-full group-hover:translate-x-full transition-transform duration-700 bg-gradient-to-r from-transparent via-white/20 to-transparent z-0" />

          <span className="relative z-10 flex items-center gap-2">
            {status === RegistrationStatus.LOADING ? (
              <>
                <Loader2 className="animate-spin w-6 h-6" />
                Registering...
              </>
            ) : (
              <>
                Register Now
                <Send className="w-5 h-5" />
              </>
            )}
          </span>
        </button>
      </div>

      {errorMsg && (
        <div className="flex items-center gap-2 text-red-500 text-sm font-medium px-2 animate-in slide-in-from-top-1 fade-in">
            <AlertCircle className="w-4 h-4 shrink-0" />
            <span>{errorMsg}</span>
        </div>
      )}
    </div>
  );
};

